fn main() {
    let command = XtaskCommand::parse(std::env::args().skip(1));
    let result = dispatch::execute(command);
    if let Err(err) = result {
        eprintln!("xtask: {err}");
        std::process::exit(1);
    }
}

fn ci_fast() -> Result<(), String> {
    run("cargo", &["fmt", "--check"])?;
    run("cargo", &["check", "--workspace", "--all-targets"])?;
    run("cargo", &["test", "--workspace"])?;
    run_policy_checks()
}

fn precommit() -> Result<(), String> {
    ensure_reports_dir()?;
    run("cargo", &["fmt", "--check"])?;
    check_static_language()?;
    check_no_panic_family()?;
    check_allow_attributes()?;
    check_local_context()?;
    check_file_policy()?;
    check_executable_files()?;
    check_workflows()?;
    check_droid_review_config()?;
    check_spec_format()?;
    check_spec_numbering()?;
    check_fixture_contracts()?;
    check_traceability()?;
    check_capabilities()?;
    check_workspace_shape()?;
    check_architecture()?;
    check_public_api()?;
    check_output_contracts()?;
    check_doc_artifacts()?;
    check_doc_index()?;
    check_readme_state()?;
    markdown_links()?;
    check_campaign()?;
    check_pr_shape()?;
    check_command_catalog()?;
    check_generated()?;
    check_badge_diff_policy()?;
    check_generated_clean()?;
    check_lint_policy()?;
    let body = precommit_report_body();
    write_report("precommit.md", &body)
}

fn check_pr() -> Result<(), String> {
    ensure_reports_dir()?;
    ci_fast()?;
    run(
        "cargo",
        &[
            "clippy",
            "--workspace",
            "--all-targets",
            "--",
            "-D",
            "warnings",
        ],
    )?;
    run("cargo", &["doc", "--workspace", "--no-deps"])?;
    pr_summary()?;
    let body = check_pr_report_body();
    write_report("check-pr.md", &body)?;
    suggested_fixes()?;
    receipts_write()?;
    pr_summary()?;
    reports_index()
}

fn run_policy_checks() -> Result<(), String> {
    check_static_language()?;
    check_no_panic_family()?;
    check_allow_attributes()?;
    check_local_context()?;
    check_file_policy()?;
    check_executable_files()?;
    check_workflows()?;
    check_droid_review_config()?;
    check_spec_format()?;
    check_spec_numbering()?;
    check_fixture_contracts()?;
    check_traceability()?;
    check_capabilities()?;
    check_workspace_shape()?;
    check_architecture()?;
    check_public_api()?;
    check_output_contracts()?;
    check_doc_artifacts()?;
    check_doc_index()?;
    check_readme_state()?;
    markdown_links()?;
    check_campaign()?;
    check_pr_shape()?;
    check_command_catalog()?;
    check_generated()?;
    check_badge_diff_policy()?;
    check_generated_clean()?;
    check_dependencies()?;
    check_process_policy()?;
    check_network_policy()?;
    check_lint_policy()
}

fn ci_full() -> Result<(), String> {
    check_pr()?;
    run_ci_full_evidence_gates(&ci_full_evidence_gates())?;
    run("cargo", &["package", "-p", "ripr", "--list"])?;
    run("cargo", &["publish", "-p", "ripr", "--dry-run"]).map(|_| ())
}

#[derive(Debug, Eq, PartialEq)]
struct CwdCommand {
    program: PathBuf,
    args: Vec<String>,
    cwd: PathBuf,
}

fn run_cwd_command(command: &CwdCommand) -> Result<(), String> {
    let args: Vec<&str> = command.args.iter().map(String::as_str).collect();
    run_in_dir(&command.program, &args, &command.cwd).map(|_| ())
}

fn vscode_compile() -> Result<(), String> {
    run_cwd_command(&vscode_compile_command())
}

fn vscode_package() -> Result<(), String> {
    let extension_dir = vscode_extension_dir();
    let dist = extension_dir.join("dist");
    fs::create_dir_all(&dist)
        .map_err(|err| format!("failed to create {}: {err}", dist.display()))?;
    let version = vscode_package_version(&extension_dir.join("package.json"))?;
    run_cwd_command(&vscode_package_command(&version))
}

fn vscode_test() -> Result<(), String> {
    vscode_compile()
}

fn vscode_test_e2e() -> Result<(), String> {
    run("cargo", &["build", "-p", "ripr"])?;
    vscode_compile()?;
    let server_path = vscode_test_server_path()?;
    let workspace_path = vscode_test_workspace_path()?;
    let envs = [
        (
            "RIPR_TEST_SERVER_PATH",
            path_to_utf8(&server_path, "VS Code test server path")?,
        ),
        (
            "RIPR_TEST_WORKSPACE_PATH",
            path_to_utf8(&workspace_path, "VS Code test workspace path")?,
        ),
    ];
    run_cwd_command_with_envs(&vscode_test_e2e_command(), &envs)
}

fn vscode_compile_command() -> CwdCommand {
    CwdCommand {
        program: vscode_local_bin("tsc"),
        args: vec!["-p".to_string(), "./".to_string()],
        cwd: vscode_extension_dir(),
    }
}

fn vscode_package_command(version: &str) -> CwdCommand {
    CwdCommand {
        program: vscode_local_bin("vsce"),
        args: vec![
            "package".to_string(),
            "--out".to_string(),
            format!("dist/ripr-{version}.vsix"),
        ],
        cwd: vscode_extension_dir(),
    }
}

fn vscode_test_e2e_command() -> CwdCommand {
    CwdCommand {
        program: PathBuf::from("node"),
        args: vec!["out/test/runTest.js".to_string()],
        cwd: vscode_extension_dir(),
    }
}

fn run_cwd_command_with_envs(command: &CwdCommand, envs: &[(&str, &str)]) -> Result<(), String> {
    let args: Vec<&str> = command.args.iter().map(String::as_str).collect();
    run_in_dir_with_envs(&command.program, &args, &command.cwd, envs).map(|_| ())
}

fn vscode_test_server_path() -> Result<PathBuf, String> {
    let binary = if cfg!(windows) { "ripr.exe" } else { "ripr" };
    let target_dir = std::env::var_os("CARGO_TARGET_DIR")
        .map(PathBuf::from)
        .unwrap_or_else(|| {
            repo_root()
                .unwrap_or_else(|_| PathBuf::from("."))
                .join("target")
        });
    Ok(target_dir.join("debug").join(binary))
}

fn vscode_test_workspace_path() -> Result<PathBuf, String> {
    Ok(repo_root()?
        .join("fixtures")
        .join("boundary_gap")
        .join("input"))
}

fn repo_root() -> Result<PathBuf, String> {
    let manifest_dir = Path::new(env!("CARGO_MANIFEST_DIR"));
    manifest_dir.parent().map(Path::to_path_buf).ok_or_else(|| {
        format!(
            "failed to resolve repo root from {}",
            manifest_dir.display()
        )
    })
}

fn path_to_utf8<'a>(path: &'a Path, label: &str) -> Result<&'a str, String> {
    path.to_str()
        .ok_or_else(|| format!("{label} is not valid UTF-8: {}", path.display()))
}

fn vscode_extension_dir() -> PathBuf {
    repo_root()
        .unwrap_or_else(|_| PathBuf::from("."))
        .join("editors/vscode")
}

fn vscode_local_bin(name: &str) -> PathBuf {
    let executable = if cfg!(windows) {
        format!("{name}.cmd")
    } else {
        name.to_string()
    };
    vscode_extension_dir()
        .join("node_modules")
        .join(".bin")
        .join(executable)
}

fn vscode_package_version(package_json: &Path) -> Result<String, String> {
    let value = read_json_value(package_json)?;
    value
        .get("version")
        .and_then(Value::as_str)
        .filter(|version| !version.trim().is_empty())
        .map(str::to_string)
        .ok_or_else(|| format!("{} is missing a string version", package_json.display()))
}

fn ci_full_evidence_gates() -> [CiFullEvidenceGate; 5] {
    [
        CiFullEvidenceGate {
            name: "fixtures",
            run: ci_full_fixtures,
        },
        CiFullEvidenceGate {
            name: "goldens check",
            run: goldens_check,
        },
        CiFullEvidenceGate {
            name: "test-oracle-report",
            run: test_oracle_report,
        },
        CiFullEvidenceGate {
            name: "dogfood",
            run: dogfood,
        },
        CiFullEvidenceGate {
            name: "metrics",
            run: metrics_report,
        },
    ]
}

fn ci_full_fixtures() -> Result<(), String> {
    fixtures(None)
}

fn run_ci_full_evidence_gates(gates: &[CiFullEvidenceGate]) -> Result<(), String> {
    for gate in gates {
        (gate.run)()
            .map_err(|err| format!("ci-full evidence gate `{}` failed: {err}", gate.name))?;
    }
    Ok(())
}

fn release_server_archive(args: &[String]) -> Result<(), String> {
    let version = required_release_arg(args, "version", "RAW_VERSION")?;
    let target = required_release_arg(args, "target", "TARGET")?;
    let executable = required_release_arg(args, "executable", "EXECUTABLE")?;
    let archive = required_release_arg(args, "archive", "ARCHIVE")?;
    let version = normalize_release_version(&version);
    let asset_name = format!("ripr-server-v{version}-{target}.{archive}");
    let package_dir = Path::new("package");
    let dist_dir = Path::new("dist");

    if package_dir.exists() {
        fs::remove_dir_all(package_dir)
            .map_err(|err| format!("failed to remove {}: {err}", package_dir.display()))?;
    }
    fs::create_dir_all(package_dir)
        .map_err(|err| format!("failed to create {}: {err}", package_dir.display()))?;
    fs::create_dir_all(dist_dir)
        .map_err(|err| format!("failed to create {}: {err}", dist_dir.display()))?;

    let built_executable = Path::new("target")
        .join(&target)
        .join("release")
        .join(&executable);
    fs::copy(&built_executable, package_dir.join(&executable)).map_err(|err| {
        format!(
            "failed to copy {} into {}: {err}",
            built_executable.display(),
            package_dir.display()
        )
    })?;
    copy_release_file("LICENSE-MIT", package_dir)?;
    copy_release_file("LICENSE-APACHE", package_dir)?;
    fs::write(
        package_dir.join("README-server.txt"),
        release_server_readme(&version),
    )
    .map_err(|err| {
        format!(
            "failed to write {}: {err}",
            package_dir.join("README-server.txt").display()
        )
    })?;

    let asset_path = dist_dir.join(&asset_name);
    if asset_path.exists() {
        fs::remove_file(&asset_path)
            .map_err(|err| format!("failed to remove {}: {err}", asset_path.display()))?;
    }
    match archive.as_str() {
        "zip" => create_zip_archive(package_dir, &asset_path)?,
        "tar.gz" => create_tar_gz_archive(package_dir, &asset_path)?,
        other => {
            return Err(format!(
                "unsupported release server archive format `{other}`"
            ));
        }
    }

    let sha = sha256_file(&asset_path)?;
    fs::write(
        dist_dir.join(format!("{asset_name}.sha256")),
        format!("{sha}\n"),
    )
    .map_err(|err| {
        format!(
            "failed to write {}: {err}",
            dist_dir.join(format!("{asset_name}.sha256")).display()
        )
    })?;
    eprintln!("wrote {}", asset_path.display());
    Ok(())
}

fn release_server_manifest(args: &[String]) -> Result<(), String> {
    let version = required_release_arg(args, "version", "RAW_VERSION")?;
    let repository = required_release_arg(args, "repository", "REPOSITORY")?;
    let version = normalize_release_version(&version);
    let dist_dir = Path::new("dist");
    let checksums_path = dist_dir.join("checksums.txt");
    if checksums_path.exists() {
        fs::remove_file(&checksums_path)
            .map_err(|err| format!("failed to remove {}: {err}", checksums_path.display()))?;
    }

    let mut assets = serde_json::Map::new();
    for asset in release_server_assets(dist_dir, &version)? {
        let sha_path = dist_dir.join(format!("{}.sha256", asset.file_name));
        let sha = read_trimmed(&sha_path)?;
        let url = format!(
            "https://github.com/{repository}/releases/download/v{version}/{}",
            asset.file_name
        );
        assets.insert(
            asset.target,
            serde_json::json!({ "url": url, "sha256": sha }),
        );
    }

    let manifest = serde_json::json!({
        "version": version,
        "assets": assets,
    });
    let manifest_path = dist_dir.join(format!("ripr-server-manifest-v{version}.json"));
    let manifest_text = serde_json::to_string_pretty(&manifest)
        .map_err(|err| format!("failed to render release server manifest: {err}"))?;
    fs::write(&manifest_path, format!("{manifest_text}\n"))
        .map_err(|err| format!("failed to write {}: {err}", manifest_path.display()))?;

    let mut checksum_lines = Vec::new();
    for path in sorted_dist_files(dist_dir)? {
        let Some(file_name) = path.file_name().and_then(|name| name.to_str()) else {
            continue;
        };
        if file_name.ends_with(".sha256") || file_name == "checksums.txt" {
            continue;
        }
        checksum_lines.push(format!("{}  {file_name}", sha256_file(&path)?));
    }
    fs::write(&checksums_path, format!("{}\n", checksum_lines.join("\n")))
        .map_err(|err| format!("failed to write {}: {err}", checksums_path.display()))?;
    eprintln!("wrote {}", manifest_path.display());
    eprintln!("wrote {}", checksums_path.display());
    Ok(())
}

fn release_upload_assets(args: &[String]) -> Result<(), String> {
    let version = normalize_release_version(&required_release_arg(args, "version", "RAW_VERSION")?);
    let tag = format!("v{version}");
    if !command_success_owned(
        "gh",
        &["release".to_string(), "view".to_string(), tag.clone()],
    )? {
        run_owned(
            "gh",
            &[
                "release".to_string(),
                "create".to_string(),
                tag.clone(),
                "--title".to_string(),
                format!("ripr {version}"),
            ],
        )?;
    }

    let mut upload_args = vec!["release".to_string(), "upload".to_string(), tag];
    for path in sorted_dist_files(Path::new("dist"))? {
        upload_args.push(path.to_string_lossy().to_string());
    }
    upload_args.push("--clobber".to_string());
    run_owned("gh", &upload_args)
}

#[derive(Debug, Eq, PartialEq)]
struct ReleaseServerAsset {
    target: String,
    file_name: String,
}

fn release_server_assets(
    dist_dir: &Path,
    version: &str,
) -> Result<Vec<ReleaseServerAsset>, String> {
    let prefix = format!("ripr-server-v{version}-");
    let mut assets = Vec::new();
    for path in sorted_dist_files(dist_dir)? {
        let Some(file_name) = path.file_name().and_then(|name| name.to_str()) else {
            continue;
        };
        let Some(target_with_suffix) = file_name.strip_prefix(&prefix) else {
            continue;
        };
        let target = target_with_suffix
            .strip_suffix(".tar.gz")
            .or_else(|| target_with_suffix.strip_suffix(".zip"));
        let Some(target) = target else {
            continue;
        };
        assets.push(ReleaseServerAsset {
            target: target.to_string(),
            file_name: file_name.to_string(),
        });
    }
    Ok(assets)
}

fn required_release_arg(args: &[String], flag: &str, env_name: &str) -> Result<String, String> {
    let flag_name = format!("--{flag}");
    for window in args.windows(2) {
        if window[0] == flag_name {
            return Ok(window[1].clone());
        }
    }
    let inline_prefix = format!("{flag_name}=");
    for arg in args {
        if let Some(value) = arg.strip_prefix(&inline_prefix) {
            return Ok(value.to_string());
        }
    }
    std::env::var(env_name).map_err(|err| format!("missing {flag_name} or {env_name}: {err}"))
}

fn normalize_release_version(version: &str) -> String {
    version.trim().trim_start_matches('v').to_string()
}

fn copy_release_file(file_name: &str, package_dir: &Path) -> Result<(), String> {
    fs::copy(file_name, package_dir.join(file_name)).map_err(|err| {
        format!(
            "failed to copy {file_name} into {}: {err}",
            package_dir.display()
        )
    })?;
    Ok(())
}

fn release_server_readme(version: &str) -> String {
    format!(
        "ripr server {version}\n\nThis archive contains the ripr executable used by the VS Code/Open VSX\nextension. It is distributed under MIT OR Apache-2.0."
    )
}

fn create_tar_gz_archive(package_dir: &Path, asset_path: &Path) -> Result<(), String> {
    run_owned(
        "tar",
        &[
            "-czf".to_string(),
            asset_path.to_string_lossy().to_string(),
            "-C".to_string(),
            package_dir.to_string_lossy().to_string(),
            ".".to_string(),
        ],
    )
}

fn create_zip_archive(package_dir: &Path, asset_path: &Path) -> Result<(), String> {
    let file = fs::File::create(asset_path)
        .map_err(|err| format!("failed to create {}: {err}", asset_path.display()))?;
    let mut writer = zip::ZipWriter::new(file);
    let options: zip::write::FileOptions<'_, ()> = zip::write::FileOptions::default()
        .compression_method(zip::CompressionMethod::Deflated)
        .unix_permissions(0o644);

    let entries = fs::read_dir(package_dir)
        .map_err(|err| format!("failed to read {}: {err}", package_dir.display()))?;
    let mut sorted: Vec<PathBuf> = entries
        .filter_map(|entry| entry.ok().map(|entry| entry.path()))
        .collect();
    sorted.sort();

    for path in sorted {
        let metadata = fs::metadata(&path)
            .map_err(|err| format!("failed to stat {}: {err}", path.display()))?;
        if !metadata.is_file() {
            return Err(format!(
                "release server package directory must be flat; found non-file `{}`",
                path.display()
            ));
        }
        let file_name = path
            .file_name()
            .and_then(|name| name.to_str())
            .ok_or_else(|| format!("invalid file name in {}", path.display()))?
            .to_string();
        let entry_options = if file_name.ends_with(".exe") {
            options.unix_permissions(0o755)
        } else if metadata.permissions().readonly() {
            options
        } else {
            // Best-effort executable bit for Unix-style binaries (ripr) without an extension.
            if !file_name.contains('.') {
                options.unix_permissions(0o755)
            } else {
                options
            }
        };
        writer
            .start_file(&file_name, entry_options)
            .map_err(|err| format!("failed to start zip entry {file_name}: {err}"))?;
        let mut input = fs::File::open(&path)
            .map_err(|err| format!("failed to open {} for zip: {err}", path.display()))?;
        std::io::copy(&mut input, &mut writer)
            .map_err(|err| format!("failed to write zip entry {file_name}: {err}"))?;
    }
    writer
        .finish()
        .map_err(|err| format!("failed to finalize {}: {err}", asset_path.display()))?;
    Ok(())
}

fn sha256_file(path: &Path) -> Result<String, String> {
    let mut file = fs::File::open(path)
        .map_err(|err| format!("failed to open {} for hashing: {err}", path.display()))?;
    let mut hasher = Sha256::new();
    let mut buffer = [0_u8; 8192];
    loop {
        let read = file
            .read(&mut buffer)
            .map_err(|err| format!("failed to read {} for hashing: {err}", path.display()))?;
        if read == 0 {
            break;
        }
        hasher.update(&buffer[..read]);
    }
    Ok(hex_lower(&hasher.finalize()))
}

fn hex_lower(bytes: &[u8]) -> String {
    const HEX: &[u8; 16] = b"0123456789abcdef";
    let mut output = String::with_capacity(bytes.len() * 2);
    for byte in bytes {
        output.push(char::from(HEX[usize::from(byte >> 4)]));
        output.push(char::from(HEX[usize::from(byte & 0x0f)]));
    }
    output
}

fn sorted_dist_files(dist_dir: &Path) -> Result<Vec<PathBuf>, String> {
    let mut paths = Vec::new();
    for entry in fs::read_dir(dist_dir)
        .map_err(|err| format!("failed to read {}: {err}", dist_dir.display()))?
    {
        let path = entry
            .map_err(|err| format!("failed to read entry under {}: {err}", dist_dir.display()))?
            .path();
        if path.is_file() {
            paths.push(path);
        }
    }
    paths.sort();
    Ok(paths)
}

fn read_trimmed(path: &Path) -> Result<String, String> {
    fs::read_to_string(path)
        .map(|text| text.trim().to_string())
        .map_err(|err| format!("failed to read {}: {err}", path.display()))
}

const RIPR_MANAGED_PRE_COMMIT_MARKER: &str = "# ripr-managed pre-commit hook";

fn install_hooks(args: &[String]) -> Result<(), String> {
    if !args.is_empty() {
        return Err("install-hooks does not accept arguments".to_string());
    }

    let hook = install_hooks_in(Path::new("."))?;
    eprintln!("installed hook: {}", hook.display());
    Ok(())
}

fn install_hooks_in(root: &Path) -> Result<PathBuf, String> {
    let git_dir = root.join(".git");
    if !git_dir.is_dir() {
        return Err(format!(
            "missing .git directory under {}; run from a git worktree",
            root.display()
        ));
    }

    let hooks_dir = git_dir.join("hooks");
    fs::create_dir_all(&hooks_dir)
        .map_err(|err| format!("failed to create {}: {err}", hooks_dir.display()))?;

    let hook = hooks_dir.join("pre-commit");
    if hook.exists() {
        let current = fs::read_to_string(&hook)
            .map_err(|err| format!("failed to read {}: {err}", hook.display()))?;
        if !is_ripr_managed_hook(&current) {
            return Err(format!(
                "refusing to overwrite unmanaged hook at {}; remove it or install the ripr precommit hook manually",
                hook.display()
            ));
        }
    }

    fs::write(&hook, ripr_pre_commit_hook())
        .map_err(|err| format!("failed to write {}: {err}", hook.display()))?;
    make_hook_executable(&hook)?;
    Ok(hook)
}

fn ripr_pre_commit_hook() -> String {
    format!("#!/usr/bin/env sh\n{RIPR_MANAGED_PRE_COMMIT_MARKER}\nset -eu\ncargo xtask precommit\n")
}

fn is_ripr_managed_hook(text: &str) -> bool {
    text.contains(RIPR_MANAGED_PRE_COMMIT_MARKER)
}

#[cfg(unix)]
fn make_hook_executable(path: &Path) -> Result<(), String> {
    use std::os::unix::fs::PermissionsExt;

    let mut permissions = fs::metadata(path)
        .map_err(|err| format!("failed to read {} metadata: {err}", path.display()))?
        .permissions();
    permissions.set_mode(0o755);
    fs::set_permissions(path, permissions)
        .map_err(|err| format!("failed to set executable bit on {}: {err}", path.display()))
}

#[cfg(not(unix))]
fn make_hook_executable(_path: &Path) -> Result<(), String> {
    Ok(())
}

