fn validate_evidence_record_contract_fixture_corpus(
    violations: &mut Vec<String>,
) -> Result<(), String> {
    validate_evidence_record_contract_fixture_corpus_at(
        Path::new(EVIDENCE_RECORD_CONTRACT_CORPUS),
        violations,
    )
}

fn validate_evidence_record_contract_fixture_corpus_at(
    path: &Path,
    violations: &mut Vec<String>,
) -> Result<(), String> {
    if !path.exists() {
        violations.push(format!(
            "evidence-record contract corpus is missing {}",
            normalize_path(path)
        ));
        return Ok(());
    }

    let corpus = match read_json_value(path) {
        Ok(value) => value,
        Err(err) => {
            violations.push(err);
            return Ok(());
        }
    };
    validate_evidence_record_contract_corpus_value(path, &corpus, violations);
    Ok(())
}

fn validate_evidence_record_contract_corpus_value(
    path: &Path,
    corpus: &Value,
    violations: &mut Vec<String>,
) {
    if json_string_field(corpus, "kind").as_deref() != Some("evidence_record_contract_corpus") {
        violations.push(format!(
            "{} kind must be evidence_record_contract_corpus",
            normalize_path(path)
        ));
    }
    if json_string_field(corpus, "schema_version").as_deref() != Some("0.1") {
        violations.push(format!(
            "{} schema_version must be 0.1",
            normalize_path(path)
        ));
    }
    if json_string_field(corpus, "spec").as_deref() != Some("RIPR-SPEC-0021") {
        violations.push(format!(
            "{} spec must be RIPR-SPEC-0021",
            normalize_path(path)
        ));
    }

    let Some(cases) = corpus.get("cases").and_then(Value::as_array) else {
        violations.push(format!("{} is missing cases array", normalize_path(path)));
        return;
    };

    let mut seen = BTreeSet::new();
    for case in cases {
        let case_id = json_string_field(case, "id").unwrap_or_else(|| "unknown".to_string());
        if !seen.insert(case_id.clone()) {
            violations.push(format!("evidence-record case {case_id} is duplicated"));
        }
        if json_string_field(case, "description").is_none() {
            violations.push(format!(
                "evidence-record case {case_id} is missing description"
            ));
        }
        if json_string_field(case, "source").is_none() {
            violations.push(format!("evidence-record case {case_id} is missing source"));
        }
        match case.get("record") {
            Some(Value::Object(record)) => validate_evidence_record_contract_record(
                &case_id,
                &Value::Object(record.clone()),
                violations,
            ),
            Some(_) => violations.push(format!(
                "evidence-record case {case_id} record must be an object"
            )),
            None => violations.push(format!("evidence-record case {case_id} is missing record")),
        }
    }

    for required in EVIDENCE_RECORD_REQUIRED_CASES {
        if !seen.contains(*required) {
            violations.push(format!("evidence-record corpus is missing case {required}"));
        }
    }
}

fn validate_lane1_evidence_quality_failure_fixture_corpus(
    violations: &mut Vec<String>,
) -> Result<(), String> {
    validate_lane1_evidence_quality_failure_fixture_corpus_at(
        Path::new(LANE1_EVIDENCE_QUALITY_FAILURE_CORPUS),
        violations,
    )
}

fn validate_lane1_evidence_quality_failure_fixture_corpus_at(
    path: &Path,
    violations: &mut Vec<String>,
) -> Result<(), String> {
    if !path.exists() {
        violations.push(format!(
            "Lane 1 evidence-quality failure corpus is missing {}",
            normalize_path(path)
        ));
        return Ok(());
    }

    let corpus = match read_json_value(path) {
        Ok(value) => value,
        Err(err) => {
            violations.push(err);
            return Ok(());
        }
    };
    validate_lane1_evidence_quality_failure_corpus_value(path, &corpus, violations);
    Ok(())
}

fn validate_lane1_evidence_quality_failure_corpus_value(
    path: &Path,
    corpus: &Value,
    violations: &mut Vec<String>,
) {
    if json_string_field(corpus, "kind").as_deref() != Some("lane1_evidence_quality_failure_corpus")
    {
        violations.push(format!(
            "{} kind must be lane1_evidence_quality_failure_corpus",
            normalize_path(path)
        ));
    }
    if json_string_field(corpus, "schema_version").as_deref() != Some("0.1") {
        violations.push(format!(
            "{} schema_version must be 0.1",
            normalize_path(path)
        ));
    }
    if json_string_field(corpus, "spec").as_deref() != Some("RIPR-SPEC-0032") {
        violations.push(format!(
            "{} spec must be RIPR-SPEC-0032",
            normalize_path(path)
        ));
    }

    match corpus.get("source_report") {
        Some(source @ Value::Object(_)) => {
            require_lane1_json_string_at(source, "command", "source_report", violations);
            require_lane1_json_string_at(source, "report", "source_report", violations);
            match source.get("summary") {
                Some(summary @ Value::Object(_)) => {
                    for field in [
                        "raw_headline_gaps",
                        "canonical_gap_groups",
                        "duplicate_looking_groups",
                        "missing_discriminators",
                        "static_limitations",
                        "uncalibrated_records",
                    ] {
                        require_lane1_json_usize_at(
                            summary,
                            field,
                            "source_report.summary",
                            violations,
                        );
                    }
                }
                _ => violations.push(
                    "Lane 1 evidence-quality source_report is missing summary object".to_string(),
                ),
            }
        }
        _ => violations
            .push("Lane 1 evidence-quality corpus is missing source_report object".to_string()),
    }

    let Some(cases) = corpus.get("cases").and_then(Value::as_array) else {
        violations.push(format!("{} is missing cases array", normalize_path(path)));
        return;
    };

    let mut seen = BTreeSet::new();
    let mut has_failure_mode = false;
    let mut has_negative_guard = false;
    for case in cases {
        let case_id = json_string_field(case, "id").unwrap_or_else(|| "unknown".to_string());
        if !seen.insert(case_id.clone()) {
            violations.push(format!(
                "Lane 1 evidence-quality case {case_id} is duplicated"
            ));
        }
        validate_lane1_evidence_quality_failure_case(
            &case_id,
            case,
            &mut has_failure_mode,
            &mut has_negative_guard,
            violations,
        );
    }

    for required in LANE1_EVIDENCE_QUALITY_REQUIRED_CASES {
        if !seen.contains(*required) {
            violations.push(format!(
                "Lane 1 evidence-quality corpus is missing case {required}"
            ));
        }
    }
    if !has_failure_mode {
        violations.push(
            "Lane 1 evidence-quality corpus must include at least one failure_mode case"
                .to_string(),
        );
    }
    if !has_negative_guard {
        violations.push(
            "Lane 1 evidence-quality corpus must include at least one negative_guard case"
                .to_string(),
        );
    }
}

fn validate_lane1_evidence_quality_failure_case(
    case_id: &str,
    case: &Value,
    has_failure_mode: &mut bool,
    has_negative_guard: &mut bool,
    violations: &mut Vec<String>,
) {
    require_lane1_json_string_at(case, "description", case_id, violations);
    require_lane1_json_string_at(case, "source", case_id, violations);

    match json_string_field(case, "case_kind").as_deref() {
        Some("failure_mode") => *has_failure_mode = true,
        Some("negative_guard") => *has_negative_guard = true,
        Some(other) => violations.push(format!(
            "Lane 1 evidence-quality case {case_id} has unsupported case_kind {other}"
        )),
        None => violations.push(format!(
            "Lane 1 evidence-quality case {case_id} is missing string field case_kind"
        )),
    }

    let category = match case.get("audit_signal") {
        Some(signal @ Value::Object(_)) => {
            require_lane1_json_string_at(signal, "category", case_id, violations);
            require_lane1_json_string_at(signal, "metric_path", case_id, violations);
            require_lane1_json_string_at(signal, "evidence", case_id, violations);
            require_lane1_json_usize_at(signal, "observed_count", case_id, violations);
            json_string_field(signal, "category")
        }
        _ => {
            violations.push(format!(
                "Lane 1 evidence-quality case {case_id} is missing audit_signal object"
            ));
            None
        }
    };
    if let Some(category) = &category
        && !matches!(
            category.as_str(),
            "duplicate_canonical_gap"
                | "missing_discriminator"
                | "static_limitation"
                | "oracle_semantics"
                | "calibration_gap"
        )
    {
        violations.push(format!(
            "Lane 1 evidence-quality case {case_id} has unsupported audit category {category}"
        ));
    }

    let expected = match case.get("expected_repo_exposure") {
        Some(expected @ Value::Object(_)) => {
            require_lane1_json_string_at(expected, "source", case_id, violations);
            expected
        }
        _ => {
            violations.push(format!(
                "Lane 1 evidence-quality case {case_id} is missing expected_repo_exposure object"
            ));
            return;
        }
    };
    let record = match expected.get("evidence_record") {
        Some(record @ Value::Object(_)) => record,
        Some(_) => {
            violations.push(format!(
                "Lane 1 evidence-quality case {case_id} expected_repo_exposure.evidence_record must be an object"
            ));
            return;
        }
        None => {
            violations.push(format!(
                "Lane 1 evidence-quality case {case_id} is missing expected_repo_exposure.evidence_record"
            ));
            return;
        }
    };
    validate_lane1_evidence_quality_record(case_id, record, violations);

    require_non_empty_string_array_at(case, "expected_claims", case_id, violations);
    require_non_empty_string_array_at(case, "must_not_claim", case_id, violations);

    match category.as_deref() {
        Some("duplicate_canonical_gap") => {
            if json_string_field(record, "canonical_gap_id").is_none() {
                violations.push(format!(
                    "Lane 1 evidence-quality duplicate case {case_id} must pin canonical_gap_id"
                ));
            }
            let group_size =
                json_usize_field(record, "canonical_gap_group_size").unwrap_or_default();
            let corrected_duplicate_case = group_size == 1
                && string_array_contains_case_insensitive(case, "must_not_claim", "generic");
            if group_size <= 1 && !corrected_duplicate_case {
                violations.push(format!(
                    "Lane 1 evidence-quality duplicate case {case_id} must pin group size greater than 1 or pin corrected group size 1 with a generic identity regression guard"
                ));
            }
        }
        Some("missing_discriminator")
            if lane1_count_field(record, "missing_discriminators").unwrap_or_default() == 0 =>
        {
            violations.push(format!(
                "Lane 1 evidence-quality missing-discriminator case {case_id} must pin missing discriminator count"
            ));
        }
        Some("missing_discriminator") => {}
        Some("static_limitation") => {
            if lane1_count_field(record, "static_limitations").unwrap_or_default() == 0 {
                violations.push(format!(
                    "Lane 1 evidence-quality static-limitation case {case_id} must pin static limitation count"
                ));
            }
            if !matches!(record.get("static_limitations"), Some(Value::Array(items)) if !items.is_empty())
            {
                violations.push(format!(
                    "Lane 1 evidence-quality static-limitation case {case_id} must list static_limitations"
                ));
            }
        }
        Some("oracle_semantics") => {
            let oracle_kind = record
                .get("top_related_test")
                .and_then(|test| json_string_field(test, "oracle_kind"));
            if oracle_kind.as_deref() != Some("mock_expectation")
                && json_string_field(record, "seam_kind").as_deref() != Some("side_effect")
            {
                violations.push(format!(
                    "Lane 1 evidence-quality oracle-semantics case {case_id} must pin a mock_expectation or side_effect signal"
                ));
            }
        }
        Some("calibration_gap") => match record.get("calibration") {
            Some(calibration) => {
                if json_string_field(calibration, "availability").as_deref() != Some("not_imported")
                    || json_string_field(calibration, "agreement").as_deref()
                        != Some("no_runtime_data")
                {
                    violations.push(format!(
                        "Lane 1 evidence-quality calibration case {case_id} must stay not_imported/no_runtime_data"
                    ));
                }
            }
            None => violations.push(format!(
                "Lane 1 evidence-quality calibration case {case_id} is missing calibration"
            )),
        },
        _ => {}
    }
}

fn validate_evidence_quality_benchmark_fixture_corpus(
    violations: &mut Vec<String>,
) -> Result<(), String> {
    validate_evidence_quality_benchmark_fixture_corpus_at(
        Path::new(EVIDENCE_QUALITY_BENCHMARK_CORPUS),
        violations,
    )
}

fn validate_evidence_quality_benchmark_fixture_corpus_at(
    path: &Path,
    violations: &mut Vec<String>,
) -> Result<(), String> {
    if !path.exists() {
        violations.push(format!(
            "Lane 1 evidence-quality benchmark corpus is missing {}",
            normalize_path(path)
        ));
        return Ok(());
    }

    let corpus = match read_json_value(path) {
        Ok(value) => value,
        Err(err) => {
            violations.push(err);
            return Ok(());
        }
    };
    validate_evidence_quality_benchmark_corpus_value(path, &corpus, violations);
    Ok(())
}

fn validate_evidence_quality_benchmark_corpus_value(
    path: &Path,
    corpus: &Value,
    violations: &mut Vec<String>,
) {
    let normalized = normalize_path(path);
    if json_string_field(corpus, "kind").as_deref()
        != Some("lane1_evidence_quality_benchmark_corpus")
    {
        violations.push(format!(
            "{normalized} kind must be lane1_evidence_quality_benchmark_corpus"
        ));
    }
    if json_string_field(corpus, "schema_version").as_deref() != Some("0.1") {
        violations.push(format!("{normalized} schema_version must be 0.1"));
    }
    if json_string_field(corpus, "spec").as_deref() != Some("RIPR-SPEC-0035") {
        violations.push(format!("{normalized} spec must be RIPR-SPEC-0035"));
    }

    require_string_array_contains_all(
        corpus,
        "evidence_classes",
        EVIDENCE_QUALITY_BENCHMARK_REQUIRED_CLASSES,
        "Lane 1 evidence-quality benchmark",
        violations,
    );
    require_string_array_contains_all(
        corpus,
        "required_case_kinds",
        EVIDENCE_QUALITY_BENCHMARK_REQUIRED_CASE_KINDS,
        "Lane 1 evidence-quality benchmark",
        violations,
    );
    if !matches!(corpus.get("capability_scope"), Some(Value::Object(_))) {
        violations.push(
            "Lane 1 evidence-quality benchmark is missing capability_scope object".to_string(),
        );
    }
    if !matches!(corpus.get("calibration_scope"), Some(Value::Object(_))) {
        violations.push(
            "Lane 1 evidence-quality benchmark is missing calibration_scope object".to_string(),
        );
    }
    if !matches!(corpus.get("audit_expectations"), Some(Value::Object(_))) {
        violations.push(
            "Lane 1 evidence-quality benchmark is missing audit_expectations object".to_string(),
        );
    }

    let Some(cases) = corpus.get("cases").and_then(Value::as_array) else {
        violations.push(format!("{normalized} is missing cases array"));
        return;
    };

    let mut seen_ids = BTreeSet::new();
    let mut seen_classes = BTreeSet::new();
    let mut seen_kinds = BTreeSet::new();
    let mut has_runtime_only_guard = false;
    let mut has_line_movement_guard = false;
    for case in cases {
        let case_id = json_string_field(case, "id").unwrap_or_else(|| "unknown".to_string());
        if !seen_ids.insert(case_id.clone()) {
            violations.push(format!(
                "Lane 1 evidence-quality benchmark case {case_id} is duplicated"
            ));
        }
        validate_evidence_quality_benchmark_case(
            &case_id,
            case,
            &mut seen_classes,
            &mut seen_kinds,
            &mut has_runtime_only_guard,
            &mut has_line_movement_guard,
            violations,
        );
    }

    for required in EVIDENCE_QUALITY_BENCHMARK_REQUIRED_CLASSES {
        if !seen_classes.contains(*required) {
            violations.push(format!(
                "Lane 1 evidence-quality benchmark is missing evidence_class {required}"
            ));
        }
    }
    for required in EVIDENCE_QUALITY_BENCHMARK_REQUIRED_CASE_KINDS {
        if !seen_kinds.contains(*required) {
            violations.push(format!(
                "Lane 1 evidence-quality benchmark is missing case_kind {required}"
            ));
        }
    }
    for required in EVIDENCE_QUALITY_BENCHMARK_REQUIRED_CONFIG_POLICY_CASES {
        if !seen_ids.contains(*required) {
            violations.push(format!(
                "Lane 1 evidence-quality benchmark is missing config/policy case {required}"
            ));
        }
    }
    if !has_runtime_only_guard {
        violations.push(
            "Lane 1 evidence-quality benchmark must include a runtime-only nonstatic guard"
                .to_string(),
        );
    }
    if !has_line_movement_guard {
        violations.push(
            "Lane 1 evidence-quality benchmark must include a line-movement identity guard"
                .to_string(),
        );
    }
}

fn validate_evidence_quality_benchmark_case(
    case_id: &str,
    case: &Value,
    seen_classes: &mut BTreeSet<String>,
    seen_kinds: &mut BTreeSet<String>,
    has_runtime_only_guard: &mut bool,
    has_line_movement_guard: &mut bool,
    violations: &mut Vec<String>,
) {
    for field in ["description", "fixture_reference", "expected_claim"] {
        require_lane1_json_string_at(case, field, case_id, violations);
    }
    require_non_empty_string_array_at(case, "must_not_claim", case_id, violations);
    require_lane1_json_string_at(case, "repair_route", case_id, violations);

    let evidence_class = json_string_field(case, "evidence_class");
    match evidence_class.as_deref() {
        Some(class) if EVIDENCE_QUALITY_BENCHMARK_REQUIRED_CLASSES.contains(&class) => {
            seen_classes.insert(class.to_string());
        }
        Some(class) => violations.push(format!(
            "Lane 1 evidence-quality benchmark case {case_id} has unsupported evidence_class {class}"
        )),
        None => violations.push(format!(
            "Lane 1 evidence-quality benchmark case {case_id} is missing evidence_class"
        )),
    }

    let case_kind = json_string_field(case, "case_kind");
    match case_kind.as_deref() {
        Some(kind) if EVIDENCE_QUALITY_BENCHMARK_REQUIRED_CASE_KINDS.contains(&kind) => {
            seen_kinds.insert(kind.to_string());
        }
        Some(kind) => violations.push(format!(
            "Lane 1 evidence-quality benchmark case {case_id} has unsupported case_kind {kind}"
        )),
        None => violations.push(format!(
            "Lane 1 evidence-quality benchmark case {case_id} is missing case_kind"
        )),
    }

    match json_string_field(case, "maturity_scope").as_deref() {
        Some("static_only" | "fixture_backed" | "calibrated" | "ambiguous" | "unsupported") => {}
        Some(scope) => violations.push(format!(
            "Lane 1 evidence-quality benchmark case {case_id} has unsupported maturity_scope {scope}"
        )),
        None => violations.push(format!(
            "Lane 1 evidence-quality benchmark case {case_id} is missing maturity_scope"
        )),
    }

    match case.get("expected_repo_exposure") {
        Some(expected @ Value::Object(_)) => {
            let creates_static_gap = json_bool_field(expected, "static_gap_created");
            let record = expected.get("evidence_record");
            if evidence_class.as_deref() == Some("runtime_only_signal") {
                if creates_static_gap != Some(false) || !matches!(record, Some(Value::Null)) {
                    violations.push(format!(
                        "Lane 1 evidence-quality benchmark runtime-only case {case_id} must keep static_gap_created=false and evidence_record=null"
                    ));
                }
            } else if !matches!(record, Some(Value::Object(_))) {
                violations.push(format!(
                    "Lane 1 evidence-quality benchmark case {case_id} expected_repo_exposure.evidence_record must be an object"
                ));
            }
        }
        _ => violations.push(format!(
            "Lane 1 evidence-quality benchmark case {case_id} is missing expected_repo_exposure object"
        )),
    }

    if !matches!(case.get("expected_audit_signal"), Some(Value::Object(_))) {
        violations.push(format!(
            "Lane 1 evidence-quality benchmark case {case_id} is missing expected_audit_signal object"
        ));
    }

    if case_kind.as_deref() == Some("static_limitation") {
        if json_string_field(case, "static_limitation_category").is_none() {
            violations.push(format!(
                "Lane 1 evidence-quality benchmark static-limitation case {case_id} is missing static_limitation_category"
            ));
        }
        if audit_string(
            case,
            &[
                "expected_repo_exposure",
                "evidence_record",
                "static_limitation",
                "category",
            ],
        )
        .is_some()
        {
            violations.push(format!(
                "Lane 1 evidence-quality benchmark static-limitation case {case_id} must keep static_limitation_category at the case level"
            ));
        }
    }

    if evidence_class.as_deref() == Some("runtime_only_signal") {
        match case.get("calibration") {
            Some(calibration @ Value::Object(_)) => {
                if json_bool_field(calibration, "runtime_signal") != Some(true) {
                    violations.push(format!(
                        "Lane 1 evidence-quality benchmark runtime-only case {case_id} must set calibration.runtime_signal=true"
                    ));
                }
            }
            _ => violations.push(format!(
                "Lane 1 evidence-quality benchmark runtime-only case {case_id} is missing calibration object"
            )),
        }
        *has_runtime_only_guard = true;
    }

    if evidence_class.as_deref() == Some("ambiguous_runtime_join") {
        match case.get("calibration") {
            Some(calibration @ Value::Object(_)) => {
                if json_string_field(calibration, "join_status").as_deref() != Some("ambiguous") {
                    violations.push(format!(
                        "Lane 1 evidence-quality benchmark ambiguous join case {case_id} must set calibration.join_status=ambiguous"
                    ));
                }
            }
            _ => violations.push(format!(
                "Lane 1 evidence-quality benchmark ambiguous join case {case_id} is missing calibration object"
            )),
        }
    }

    if case_kind.as_deref() == Some("metamorphic_line_movement") {
        validate_benchmark_line_movement(case_id, case, has_line_movement_guard, violations);
    }
}

fn validate_benchmark_line_movement(
    case_id: &str,
    case: &Value,
    has_line_movement_guard: &mut bool,
    violations: &mut Vec<String>,
) {
    let Some(metamorphic @ Value::Object(_)) = case.get("metamorphic") else {
        violations.push(format!(
            "Lane 1 evidence-quality benchmark line-movement case {case_id} is missing metamorphic object"
        ));
        return;
    };
    let before_id = audit_string(metamorphic, &["before", "canonical_gap_id"]);
    let after_id = audit_string(metamorphic, &["after", "canonical_gap_id"]);
    let before_line = audit_usize(metamorphic, &["before", "line"]);
    let after_line = audit_usize(metamorphic, &["after", "line"]);
    if before_id.is_none() || before_id != after_id {
        violations.push(format!(
            "Lane 1 evidence-quality benchmark line-movement case {case_id} must preserve canonical_gap_id"
        ));
    }
    if before_line.is_none() || after_line.is_none() || before_line == after_line {
        violations.push(format!(
            "Lane 1 evidence-quality benchmark line-movement case {case_id} must move line numbers"
        ));
    }
    *has_line_movement_guard = true;
}

fn validate_finding_alignment_dogfood_fixture_corpus(
    violations: &mut Vec<String>,
) -> Result<(), String> {
    let root = Path::new("fixtures/finding-alignment-dogfood");
    for required in ["SPEC.md", "corpus.json"] {
        let path = root.join(required);
        if !path.exists() {
            violations.push(format!(
                "finding alignment dogfood fixture corpus is missing {}",
                normalize_path(&path)
            ));
        }
    }

    validate_finding_alignment_dogfood_fixture_corpus_at(
        Path::new(FINDING_ALIGNMENT_DOGFOOD_CORPUS),
        violations,
    )
}

fn validate_finding_alignment_dogfood_fixture_corpus_at(
    path: &Path,
    violations: &mut Vec<String>,
) -> Result<(), String> {
    if !path.exists() {
        violations.push(format!(
            "finding alignment dogfood corpus is missing {}",
            normalize_path(path)
        ));
        return Ok(());
    }

    let scenarios = dogfood_finding_alignment_scenarios();
    let mut seen = BTreeMap::new();
    for scenario in &scenarios {
        if seen
            .insert(scenario.name.clone(), scenario.gap_state.clone())
            .is_some()
        {
            violations.push(format!(
                "finding alignment dogfood case {} is duplicated",
                scenario.name
            ));
        }
        let run = dogfood_finding_alignment_run(scenario);
        for error in run.errors {
            violations.push(format!(
                "finding alignment dogfood case {}: {error}",
                scenario.name
            ));
        }
    }

    for (case_id, gap_state) in FINDING_ALIGNMENT_DOGFOOD_REQUIRED_CASES {
        match seen.get(*case_id) {
            Some(actual) if actual == gap_state => {}
            Some(actual) => violations.push(format!(
                "finding alignment dogfood case {case_id} must have gap_state {gap_state}, got {actual}"
            )),
            None => violations.push(format!(
                "finding alignment dogfood corpus is missing case {case_id}"
            )),
        }
    }

    Ok(())
}

fn validate_swarm_plan_packet_fixture_corpus(violations: &mut Vec<String>) -> Result<(), String> {
    let root = Path::new("fixtures/swarm-plan-packet-corpus");
    for required in ["SPEC.md", "corpus.json"] {
        let path = root.join(required);
        if !path.exists() {
            violations.push(format!(
                "swarm plan packet fixture corpus is missing {}",
                normalize_path(&path)
            ));
        }
    }
    let spec = root.join("SPEC.md");
    if spec.exists() {
        let spec_text = read_text_lossy(&spec)?;
        if !spec_text
            .lines()
            .any(|line| line.starts_with("Spec: RIPR-SPEC-0057"))
        {
            violations.push(format!(
                "{} is missing `Spec: RIPR-SPEC-0057`",
                normalize_path(&spec)
            ));
        }
        for heading in ["## Given", "## When", "## Then", "## Must Not"] {
            if !has_markdown_heading(&spec_text, heading) {
                violations.push(format!("{} is missing `{heading}`", normalize_path(&spec)));
            }
        }
    }

    validate_swarm_plan_packet_fixture_corpus_at(Path::new(SWARM_PLAN_PACKET_CORPUS), violations)
}

fn validate_swarm_plan_packet_fixture_corpus_at(
    path: &Path,
    violations: &mut Vec<String>,
) -> Result<(), String> {
    if !path.exists() {
        violations.push(format!(
            "swarm plan packet corpus is missing {}",
            normalize_path(path)
        ));
        return Ok(());
    }

    let corpus = match read_json_value(path) {
        Ok(value) => value,
        Err(err) => {
            violations.push(err);
            return Ok(());
        }
    };
    if json_string_field(&corpus, "kind").as_deref() != Some("swarm_plan_packet_corpus") {
        violations.push(format!(
            "{} kind must be swarm_plan_packet_corpus",
            normalize_path(path)
        ));
    }
    if json_string_field(&corpus, "schema_version").as_deref() != Some("0.1") {
        violations.push(format!(
            "{} schema_version must be 0.1",
            normalize_path(path)
        ));
    }
    if json_string_field(&corpus, "spec").as_deref() != Some("RIPR-SPEC-0057") {
        violations.push(format!(
            "{} spec must be RIPR-SPEC-0057",
            normalize_path(path)
        ));
    }

    let Some(cases) = corpus.get("cases").and_then(Value::as_array) else {
        violations.push(format!("{} is missing cases array", normalize_path(path)));
        return Ok(());
    };
    let mut seen = BTreeMap::new();
    for case in cases {
        let case_id = json_string_field(case, "id").unwrap_or_else(|| "unknown".to_string());
        if seen
            .insert(
                case_id.clone(),
                json_string_field(case.get("expected").unwrap_or(&Value::Null), "swarm_state")
                    .unwrap_or_default(),
            )
            .is_some()
        {
            violations.push(format!("swarm plan packet case {case_id} is duplicated"));
        }
        validate_swarm_plan_packet_fixture_case(case, &case_id, violations);
    }

    for (case_id, expected_state) in SWARM_PLAN_PACKET_REQUIRED_CASES {
        match seen.get(*case_id) {
            Some(actual) if actual == expected_state => {}
            Some(actual) => violations.push(format!(
                "swarm plan packet case {case_id} must have state {expected_state}, got {actual}"
            )),
            None => violations.push(format!(
                "swarm plan packet corpus is missing case {case_id}"
            )),
        }
    }

    Ok(())
}

fn validate_swarm_plan_packet_fixture_case(
    case: &Value,
    case_id: &str,
    violations: &mut Vec<String>,
) {
    if json_string_field(case, "description").is_none() {
        violations.push(format!(
            "swarm plan packet case {case_id} is missing description"
        ));
    }
    require_non_empty_string_array_at(case, "must_not_claim", case_id, violations);

    let Some(packet) = case.get("packet").filter(|value| value.is_object()) else {
        violations.push(format!(
            "swarm plan packet case {case_id} is missing packet object"
        ));
        return;
    };
    if !matches!(packet.get("raw_findings"), Some(Value::Array(values)) if !values.is_empty()) {
        violations.push(format!(
            "swarm plan packet case {case_id} must keep raw_findings as supporting evidence"
        ));
    }
    if let Some(receipt_command) = audit_non_empty_string(packet, &["receipt_command_or_path"])
        .or_else(|| audit_non_empty_string(packet, &["receipt_command"]))
        && !ripr_swarm_plan_fixture_receipt_command_supported(&receipt_command)
    {
        violations.push(format!(
            "swarm plan packet case {case_id} uses unsupported receipt_command `{receipt_command}`"
        ));
    }

    let Some(expected) = case.get("expected").filter(|value| value.is_object()) else {
        violations.push(format!(
            "swarm plan packet case {case_id} is missing expected object"
        ));
        return;
    };

    let actionable_gaps = serde_json::json!({
        "schema_version": "0.1",
        "tool": "ripr",
        "report": "actionable-gaps",
        "summary": {"actionable_gaps": 1},
        "packets": [packet.clone()]
    });
    let report = ripr_swarm_plan_from_actionable_gaps_value(
        10,
        Path::new("target/ripr/reports/actionable-gaps.json"),
        &actionable_gaps,
    );
    if report.packets.len() != 1 {
        violations.push(format!(
            "swarm plan packet case {case_id} produced {} packets, expected 1",
            report.packets.len()
        ));
        return;
    }
    let planned = &report.packets[0];

    if let Some(expected_state) = json_string_field(expected, "swarm_state") {
        if planned.swarm_state != expected_state {
            violations.push(format!(
                "swarm plan packet case {case_id} state must be {expected_state}, got {}",
                planned.swarm_state
            ));
        }
    } else {
        violations.push(format!(
            "swarm plan packet case {case_id} expected.swarm_state is missing"
        ));
    }

    if let Some(expected_ready) = json_bool_field(expected, "swarm_ready") {
        let actual_ready = planned.swarm_state == "queued";
        if actual_ready != expected_ready {
            violations.push(format!(
                "swarm plan packet case {case_id} ready must be {expected_ready}, got {actual_ready}"
            ));
        }
    }
    if let Some(expected_high_confidence) = json_bool_field(expected, "high_confidence") {
        let actual_high_confidence = ripr_swarm_plan_packet_is_high_confidence(planned);
        if actual_high_confidence != expected_high_confidence {
            violations.push(format!(
                "swarm plan packet case {case_id} high_confidence must be {expected_high_confidence}, got {actual_high_confidence}"
            ));
        }
    }

    let expected_missing_context = json_string_array_field(expected, "missing_context");
    if planned.missing_context != expected_missing_context {
        violations.push(format!(
            "swarm plan packet case {case_id} missing_context must be [{}], got [{}]",
            expected_missing_context.join(", "),
            planned.missing_context.join(", ")
        ));
    }
    let expected_blocked_reasons = json_string_array_field(expected, "blocked_reasons");
    if planned.blocked_reasons != expected_blocked_reasons {
        violations.push(format!(
            "swarm plan packet case {case_id} blocked_reasons must be [{}], got [{}]",
            expected_blocked_reasons.join(", "),
            planned.blocked_reasons.join(", ")
        ));
    }

    let output_packet = ripr_swarm_plan_packets_json(std::slice::from_ref(planned))
        .into_iter()
        .next()
        .unwrap_or(Value::Null);
    if output_packet
        .get("raw_findings_supporting_only")
        .and_then(Value::as_bool)
        != Some(true)
    {
        violations.push(format!(
            "swarm plan packet case {case_id} must emit raw_findings_supporting_only"
        ));
    }

    let Some(summary) = expected.get("summary").and_then(Value::as_object) else {
        violations.push(format!(
            "swarm plan packet case {case_id} expected.summary is missing"
        ));
        return;
    };
    let actual_summary = ripr_swarm_plan_summary_json(&report);
    for (key, expected_value) in summary {
        let Some(expected_count) = expected_value.as_u64() else {
            violations.push(format!(
                "swarm plan packet case {case_id} expected.summary.{key} must be numeric"
            ));
            continue;
        };
        let actual_count = actual_summary.get(key).and_then(Value::as_u64);
        if actual_count != Some(expected_count) {
            violations.push(format!(
                "swarm plan packet case {case_id} summary.{key} must be {expected_count}, got {}",
                actual_count
                    .map(|value| value.to_string())
                    .unwrap_or_else(|| "missing".to_string())
            ));
        }
    }
}

fn validate_actionable_gap_outcomes_fixture_corpus(
    violations: &mut Vec<String>,
) -> Result<(), String> {
    let root = Path::new("fixtures/actionable-gap-outcomes-corpus");
    for required in ["SPEC.md", "corpus.json"] {
        let path = root.join(required);
        if !path.exists() {
            violations.push(format!(
                "actionable gap outcomes fixture corpus is missing {}",
                normalize_path(&path)
            ));
        }
    }
    let spec = root.join("SPEC.md");
    if spec.exists() {
        let spec_text = read_text_lossy(&spec)?;
        if !spec_text
            .lines()
            .any(|line| line.starts_with("Spec: RIPR-SPEC-0031"))
        {
            violations.push(format!(
                "{} is missing `Spec: RIPR-SPEC-0031`",
                normalize_path(&spec)
            ));
        }
        if !spec_text
            .lines()
            .any(|line| line.starts_with("Related: RIPR-SPEC-0057"))
        {
            violations.push(format!(
                "{} is missing `Related: RIPR-SPEC-0057`",
                normalize_path(&spec)
            ));
        }
        for heading in ["## Given", "## When", "## Then", "## Must Not"] {
            if !has_markdown_heading(&spec_text, heading) {
                violations.push(format!("{} is missing `{heading}`", normalize_path(&spec)));
            }
        }
    }

    validate_actionable_gap_outcomes_fixture_corpus_at(
        Path::new(ACTIONABLE_GAP_OUTCOMES_CORPUS),
        violations,
    )
}

fn validate_actionable_gap_outcomes_fixture_corpus_at(
    path: &Path,
    violations: &mut Vec<String>,
) -> Result<(), String> {
    if !path.exists() {
        violations.push(format!(
            "actionable gap outcomes corpus is missing {}",
            normalize_path(path)
        ));
        return Ok(());
    }

    let corpus = match read_json_value(path) {
        Ok(value) => value,
        Err(err) => {
            violations.push(err);
            return Ok(());
        }
    };
    if json_string_field(&corpus, "kind").as_deref() != Some("actionable_gap_outcomes_corpus") {
        violations.push(format!(
            "{} kind must be actionable_gap_outcomes_corpus",
            normalize_path(path)
        ));
    }
    if json_string_field(&corpus, "schema_version").as_deref() != Some("0.1") {
        violations.push(format!(
            "{} schema_version must be 0.1",
            normalize_path(path)
        ));
    }
    if json_string_field(&corpus, "spec").as_deref() != Some("RIPR-SPEC-0031") {
        violations.push(format!(
            "{} spec must be RIPR-SPEC-0031",
            normalize_path(path)
        ));
    }
    if json_string_field(&corpus, "related_spec").as_deref() != Some("RIPR-SPEC-0057") {
        violations.push(format!(
            "{} related_spec must be RIPR-SPEC-0057",
            normalize_path(path)
        ));
    }

    let Some(cases) = corpus.get("cases").and_then(Value::as_array) else {
        violations.push(format!("{} is missing cases array", normalize_path(path)));
        return Ok(());
    };
    let mut seen = BTreeMap::new();
    for case in cases {
        let case_id = json_string_field(case, "id").unwrap_or_else(|| "unknown".to_string());
        if seen
            .insert(
                case_id.clone(),
                actionable_gap_outcomes_expected_case_state(case).unwrap_or_default(),
            )
            .is_some()
        {
            violations.push(format!(
                "actionable gap outcomes case {case_id} is duplicated"
            ));
        }
        validate_actionable_gap_outcomes_fixture_case(case, &case_id, violations)?;
    }

    for (case_id, expected_state, expected_receipt_state) in ACTIONABLE_GAP_OUTCOMES_REQUIRED_CASES
    {
        match seen.get(*case_id) {
            Some((actual_state, actual_receipt_state))
                if actual_state == expected_state && actual_receipt_state == expected_receipt_state => {}
            Some((actual_state, actual_receipt_state)) => violations.push(format!(
                "actionable gap outcomes case {case_id} must have state {expected_state}/{expected_receipt_state}, got {actual_state}/{actual_receipt_state}"
            )),
            None => violations.push(format!(
                "actionable gap outcomes corpus is missing case {case_id}"
            )),
        }
    }

    Ok(())
}

fn actionable_gap_outcomes_expected_case_state(case: &Value) -> Option<(String, String)> {
    let outcome = audit_array(case, &["expected", "outcomes"]).first()?;
    Some((
        json_string_field(outcome, "outcome_state")?,
        json_string_field(outcome, "receipt_state")?,
    ))
}

fn validate_actionable_gap_outcomes_fixture_case(
    case: &Value,
    case_id: &str,
    violations: &mut Vec<String>,
) -> Result<(), String> {
    if json_string_field(case, "description").is_none() {
        violations.push(format!(
            "actionable gap outcomes case {case_id} is missing description"
        ));
    }
    require_actionable_gap_outcomes_string_array_at(case, "must_not_claim", case_id, violations);

    let Some(actionable_gaps) = case
        .get("actionable_gaps")
        .filter(|value| value.is_object())
    else {
        violations.push(format!(
            "actionable gap outcomes case {case_id} is missing actionable_gaps object"
        ));
        return Ok(());
    };
    if audit_array(actionable_gaps, &["packets"]).is_empty() {
        violations.push(format!(
            "actionable gap outcomes case {case_id} actionable_gaps.packets must not be empty"
        ));
        return Ok(());
    }
    for packet in audit_array(actionable_gaps, &["packets"]) {
        let packet_id =
            json_string_field(packet, "canonical_gap_id").unwrap_or_else(|| "unknown".to_string());
        if let Some(receipt_command) = audit_non_empty_string(packet, &["receipt_command_or_path"])
            .or_else(|| audit_non_empty_string(packet, &["receipt_command"]))
            && !ripr_swarm_plan_fixture_receipt_command_supported(&receipt_command)
        {
            violations.push(format!(
                "actionable gap outcomes case {case_id} packet {packet_id} uses unsupported receipt command `{receipt_command}`"
            ));
        }
    }

    let Some(expected) = case.get("expected").filter(|value| value.is_object()) else {
        violations.push(format!(
            "actionable gap outcomes case {case_id} is missing expected object"
        ));
        return Ok(());
    };
    let expected_outcomes = audit_array(expected, &["outcomes"]);
    if expected_outcomes.is_empty() {
        violations.push(format!(
            "actionable gap outcomes case {case_id} expected.outcomes must not be empty"
        ));
        return Ok(());
    }

    let agent_receipt = actionable_gap_outcomes_optional_fixture_input(case, "agent_receipt");
    let targeted_test_outcome =
        actionable_gap_outcomes_optional_fixture_input(case, "targeted_test_outcome");
    if let Some(targeted_test_outcome) = targeted_test_outcome {
        validate_actionable_gap_outcomes_targeted_shape(case_id, targeted_test_outcome, violations);
    }
    let report = match actionable_gap_outcomes_report_from_values(
        actionable_gaps,
        agent_receipt,
        targeted_test_outcome,
        format!(
            "{}#{case_id}:actionable_gaps",
            ACTIONABLE_GAP_OUTCOMES_CORPUS
        ),
        agent_receipt
            .map(|_| format!("{}#{case_id}:agent_receipt", ACTIONABLE_GAP_OUTCOMES_CORPUS)),
        targeted_test_outcome.map(|_| {
            format!(
                "{}#{case_id}:targeted_test_outcome",
                ACTIONABLE_GAP_OUTCOMES_CORPUS
            )
        }),
    ) {
        Ok(report) => report,
        Err(err) => {
            violations.push(format!(
                "actionable gap outcomes case {case_id} failed to build report: {err}"
            ));
            return Ok(());
        }
    };

    for expected_outcome in expected_outcomes {
        validate_actionable_gap_outcomes_expected_outcome(
            case_id,
            expected_outcome,
            &report,
            violations,
        );
    }

    let rendered = match actionable_gap_outcomes_json(&report) {
        Ok(json) => json,
        Err(err) => {
            violations.push(format!(
                "actionable gap outcomes case {case_id} failed to render JSON: {err}"
            ));
            return Ok(());
        }
    };
    let rendered: Value = match serde_json::from_str(&rendered) {
        Ok(value) => value,
        Err(err) => {
            violations.push(format!(
                "actionable gap outcomes case {case_id} rendered invalid JSON: {err}"
            ));
            return Ok(());
        }
    };
    validate_actionable_gap_outcomes_expected_summary(case_id, expected, &rendered, violations);
    validate_actionable_gap_outcomes_expected_orphaned_receipts(
        case_id, expected, &rendered, violations,
    );
    let markdown = actionable_gap_outcomes_markdown(&report);
    if !markdown.contains("# Actionable Gap Outcomes") {
        violations.push(format!(
            "actionable gap outcomes case {case_id} markdown must include report heading"
        ));
    }

    Ok(())
}

fn actionable_gap_outcomes_optional_fixture_input<'a>(
    case: &'a Value,
    field: &str,
) -> Option<&'a Value> {
    case.get(field).filter(|value| !value.is_null())
}

fn validate_actionable_gap_outcomes_targeted_shape(
    case_id: &str,
    targeted_test_outcome: &Value,
    violations: &mut Vec<String>,
) {
    for bucket in ["moved", "unchanged", "regressed"] {
        for item in audit_array(targeted_test_outcome, &[bucket]) {
            for field in ["before", "after", "direction"] {
                if audit_non_empty_string(item, &[field]).is_none() {
                    violations.push(format!(
                        "actionable gap outcomes case {case_id} targeted_test_outcome.{bucket} item must include {field}"
                    ));
                }
            }
        }
    }
    for bucket in ["removed", "new"] {
        for item in audit_array(targeted_test_outcome, &[bucket]) {
            if audit_non_empty_string(item, &["grip_class"]).is_none() {
                violations.push(format!(
                    "actionable gap outcomes case {case_id} targeted_test_outcome.{bucket} item must include grip_class"
                ));
            }
            for field in ["before", "after", "direction"] {
                if item.get(field).is_some_and(|value| !value.is_null()) {
                    violations.push(format!(
                        "actionable gap outcomes case {case_id} targeted_test_outcome.{bucket} item must use one-sided grip_class instead of {field}"
                    ));
                }
            }
        }
    }
}

fn validate_actionable_gap_outcomes_expected_outcome(
    case_id: &str,
    expected: &Value,
    report: &ActionableGapOutcomesReport,
    violations: &mut Vec<String>,
) {
    let Some(canonical_gap_id) = json_string_field(expected, "canonical_gap_id") else {
        violations.push(format!(
            "actionable gap outcomes case {case_id} expected outcome is missing canonical_gap_id"
        ));
        return;
    };
    let Some(actual) = report
        .outcomes
        .iter()
        .find(|outcome| outcome.canonical_gap_id == canonical_gap_id)
    else {
        violations.push(format!(
            "actionable gap outcomes case {case_id} did not produce outcome {canonical_gap_id}"
        ));
        return;
    };

    for (field, actual_value) in [
        ("outcome_state", actual.outcome_state.as_str()),
        ("receipt_state", actual.receipt_state.as_str()),
    ] {
        let Some(expected_value) = json_string_field(expected, field) else {
            violations.push(format!(
                "actionable gap outcomes case {case_id} expected outcome {canonical_gap_id} is missing {field}"
            ));
            continue;
        };
        if actual_value != expected_value.as_str() {
            violations.push(format!(
                "actionable gap outcomes case {case_id} outcome {canonical_gap_id} {field} must be {expected_value}, got {actual_value}"
            ));
        }
    }

    for (field, actual_value) in [
        (
            "movement_source",
            actual.movement_source.as_deref().map(Value::from),
        ),
        (
            "movement_direction",
            actual.movement_direction.as_deref().map(Value::from),
        ),
        ("before", actual.before.as_deref().map(Value::from)),
        ("after", actual.after.as_deref().map(Value::from)),
    ] {
        if let Some(expected_value) = expected.get(field) {
            let actual_value = actual_value.unwrap_or(Value::Null);
            if actual_value != *expected_value {
                violations.push(format!(
                    "actionable gap outcomes case {case_id} outcome {canonical_gap_id} {field} must be {expected_value}, got {actual_value}"
                ));
            }
        }
    }
}

fn validate_actionable_gap_outcomes_expected_summary(
    case_id: &str,
    expected: &Value,
    rendered: &Value,
    violations: &mut Vec<String>,
) {
    let Some(summary) = expected.get("summary").and_then(Value::as_object) else {
        violations.push(format!(
            "actionable gap outcomes case {case_id} expected.summary is missing"
        ));
        return;
    };
    let null_summary = Value::Null;
    let actual_summary = audit_get(rendered, &["summary"]).unwrap_or(&null_summary);
    for (key, expected_value) in summary {
        let Some(expected_count) = expected_value.as_u64() else {
            violations.push(format!(
                "actionable gap outcomes case {case_id} expected.summary.{key} must be numeric"
            ));
            continue;
        };
        let actual_count = actual_summary.get(key).and_then(Value::as_u64);
        if actual_count != Some(expected_count) {
            violations.push(format!(
                "actionable gap outcomes case {case_id} summary.{key} must be {expected_count}, got {}",
                actual_count
                    .map(|value| value.to_string())
                    .unwrap_or_else(|| "missing".to_string())
            ));
        }
    }
}

fn validate_actionable_gap_outcomes_expected_orphaned_receipts(
    case_id: &str,
    expected: &Value,
    rendered: &Value,
    violations: &mut Vec<String>,
) {
    let Some(expected_receipts) = expected.get("orphaned_receipts").and_then(Value::as_array)
    else {
        return;
    };
    let actual_receipts = audit_get(rendered, &["orphaned_receipts"])
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    for expected_receipt in expected_receipts {
        let Some(receipt_id) = json_string_field(expected_receipt, "receipt_id") else {
            violations.push(format!(
                "actionable gap outcomes case {case_id} expected orphaned receipt is missing receipt_id"
            ));
            continue;
        };
        let Some(actual) = actual_receipts.iter().find(|actual| {
            json_string_field(actual, "receipt_id").as_deref() == Some(receipt_id.as_str())
        }) else {
            violations.push(format!(
                "actionable gap outcomes case {case_id} did not produce orphaned receipt {receipt_id}"
            ));
            continue;
        };
        for field in ["seam_id", "movement_direction"] {
            if let Some(expected_value) = expected_receipt.get(field) {
                let actual_value = actual.get(field).cloned().unwrap_or(Value::Null);
                if actual_value != *expected_value {
                    violations.push(format!(
                        "actionable gap outcomes case {case_id} orphaned receipt {receipt_id} {field} must be {expected_value}, got {actual_value}"
                    ));
                }
            }
        }
    }
}

fn require_actionable_gap_outcomes_string_array_at(
    value: &Value,
    field: &str,
    case_id: &str,
    violations: &mut Vec<String>,
) {
    match value.get(field) {
        Some(Value::Array(items))
            if !items.is_empty() && items.iter().all(|item| item.as_str().is_some()) => {}
        _ => violations.push(format!(
            "actionable gap outcomes case {case_id} {field} must be a non-empty string array"
        )),
    }
}

fn ripr_swarm_plan_fixture_receipt_command_supported(command: &str) -> bool {
    let command = command.trim();
    ripr_swarm_plan_field_missing(command)
        || command == "cargo xtask receipts"
        || command == "cargo xtask receipts check"
        || command
            .strip_prefix("ripr agent receipt ")
            .is_some_and(ripr_swarm_plan_fixture_agent_receipt_args_supported)
        || command
            .strip_prefix("cargo run -p ripr -- agent receipt ")
            .is_some_and(ripr_swarm_plan_fixture_agent_receipt_args_supported)
}

fn ripr_swarm_plan_fixture_agent_receipt_args_supported(args: &str) -> bool {
    let mut has_json = false;
    let mut has_verify_json = false;
    let mut has_seam_id = false;
    let mut tokens = args.split_whitespace();
    let mut saw_any = false;

    while let Some(token) = tokens.next() {
        saw_any = true;
        match token {
            "--json" => has_json = true,
            "--root" | "--verify-json" | "--seam-id" | "--test" | "--command" | "--out" => {
                let Some(value) = tokens.next() else {
                    return false;
                };
                if value.trim().is_empty() || value.starts_with("--") {
                    return false;
                }
                match token {
                    "--verify-json" => has_verify_json = true,
                    "--seam-id" => has_seam_id = true,
                    _ => {}
                }
            }
            _ => return false,
        }
    }

    saw_any && has_json && has_verify_json && has_seam_id
}

fn validate_first_successful_pr_fixture_corpus(violations: &mut Vec<String>) -> Result<(), String> {
    let root = Path::new("fixtures/first_successful_pr");
    for required in ["README.md", "corpus.json"] {
        let path = root.join(required);
        if !path.exists() {
            violations.push(format!(
                "first successful PR fixture corpus is missing {}",
                normalize_path(&path)
            ));
        }
    }
    validate_first_successful_pr_fixture_corpus_at(
        Path::new(FIRST_SUCCESSFUL_PR_CORPUS),
        violations,
    )
}

fn validate_first_successful_pr_fixture_corpus_at(
    path: &Path,
    violations: &mut Vec<String>,
) -> Result<(), String> {
    let Some(root) = path.parent() else {
        violations.push(format!(
            "first successful PR corpus path has no parent: {}",
            normalize_path(path)
        ));
        return Ok(());
    };
    if !path.exists() {
        violations.push(format!(
            "first successful PR corpus is missing {}",
            normalize_path(path)
        ));
        return Ok(());
    }

    let corpus = match read_json_value(path) {
        Ok(value) => value,
        Err(err) => {
            violations.push(err);
            return Ok(());
        }
    };
    if json_string_field(&corpus, "kind").as_deref() != Some("first_successful_pr_corpus") {
        violations.push(format!(
            "{} kind must be first_successful_pr_corpus",
            normalize_path(path)
        ));
    }
    if json_string_field(&corpus, "schema_version").as_deref() != Some("0.1") {
        violations.push(format!(
            "{} schema_version must be 0.1",
            normalize_path(path)
        ));
    }
    if json_string_field(&corpus, "spec").as_deref() != Some("RIPR-SPEC-0051") {
        violations.push(format!(
            "{} spec must be RIPR-SPEC-0051",
            normalize_path(path)
        ));
    }

    let Some(cases) = corpus.get("cases").and_then(Value::as_array) else {
        violations.push(format!("{} is missing cases array", normalize_path(path)));
        return Ok(());
    };
    let mut seen = BTreeMap::new();
    for case in cases {
        let case_id = json_string_field(case, "id").unwrap_or_else(|| "unknown".to_string());
        if seen
            .insert(
                case_id.clone(),
                (
                    json_string_field(case, "expected_status").unwrap_or_default(),
                    json_string_field(case, "expected_state").unwrap_or_default(),
                ),
            )
            .is_some()
        {
            violations.push(format!("first successful PR case {case_id} is duplicated"));
        }
        validate_first_successful_pr_case(root, case, &case_id, violations)?;
    }
    for (case_id, expected_status, expected_state) in FIRST_SUCCESSFUL_PR_REQUIRED_CASES {
        match seen.get(*case_id) {
            Some((status, state)) if status == expected_status && state == expected_state => {}
            Some((status, state)) => violations.push(format!(
                "first successful PR case {case_id} must be {expected_status}/{expected_state}, got {status}/{state}"
            )),
            None => violations.push(format!(
                "first successful PR corpus is missing case {case_id}"
            )),
        }
    }
    Ok(())
}

fn validate_first_successful_pr_case(
    root: &Path,
    case: &Value,
    case_id: &str,
    violations: &mut Vec<String>,
) -> Result<(), String> {
    for field in ["description", "expected_status", "expected_state"] {
        if json_string_field(case, field).is_none() {
            violations.push(format!(
                "first successful PR case {case_id} is missing {field}"
            ));
        }
    }
    let case_dir = root.join(case_id);
    let input_ledger = case_dir.join("inputs/reports/gap-decision-ledger.json");
    let expected_json = case_dir.join("expected/start-here.json");
    let expected_md = case_dir.join("expected/start-here.md");
    for required in [&input_ledger, &expected_json, &expected_md] {
        if !required.exists() {
            violations.push(format!(
                "first successful PR case {case_id} is missing {}",
                normalize_path(required)
            ));
        }
    }
    if case_id == "boundary-gap" {
        validate_first_successful_pr_boundary_demo(root, case, case_id, violations)?;
    }
    if input_ledger.exists() {
        let ledger = read_json_value(&input_ledger)?;
        if json_string_field(&ledger, "kind").as_deref() != Some("gap_decision_ledger") {
            violations.push(format!(
                "first successful PR case {case_id} input ledger kind must be gap_decision_ledger"
            ));
        }
    }
    if expected_json.exists() {
        let packet = read_json_value(&expected_json)?;
        let expected_status = json_string_field(case, "expected_status").unwrap_or_default();
        let expected_state = json_string_field(case, "expected_state").unwrap_or_default();
        if json_string_field(&packet, "schema_version").as_deref() != Some("0.1") {
            violations.push(format!(
                "first successful PR case {case_id} start-here schema_version must be 0.1"
            ));
        }
        if json_string_field(&packet, "kind").as_deref() != Some("first_pr_start_here") {
            violations.push(format!(
                "first successful PR case {case_id} start-here kind must be first_pr_start_here"
            ));
        }
        if json_string_field(&packet, "status").as_deref() != Some(expected_status.as_str()) {
            violations.push(format!(
                "first successful PR case {case_id} status must be {expected_status}"
            ));
        }
        if json_string_field(&packet, "posture").as_deref() != Some("advisory") {
            violations.push(format!(
                "first successful PR case {case_id} posture must be advisory"
            ));
        }
        if audit_string(&packet, &["selected", "state"]).as_deref() != Some(expected_state.as_str())
        {
            violations.push(format!(
                "first successful PR case {case_id} selected.state must be {expected_state}"
            ));
        }
        if expected_status == "actionable"
            && audit_string(&packet, &["selected", "verify_command"]).is_none()
        {
            violations.push(format!(
                "first successful PR case {case_id} actionable packet must name verify_command"
            ));
        }
    }
    if expected_md.exists() {
        let markdown = read_text_lossy(&expected_md)?;
        for required in [
            "# RIPR First PR Start Here",
            "Status: advisory",
            "## Artifacts",
            "## Authority",
            "## Limits",
        ] {
            if !markdown.contains(required) {
                violations.push(format!(
                    "first successful PR case {case_id} Markdown is missing `{required}`"
                ));
            }
        }
        match json_string_field(case, "expected_status").as_deref() {
            Some("actionable") if !markdown.contains("## Recommendation") => violations.push(
                format!("first successful PR case {case_id} Markdown must show Recommendation"),
            ),
            Some("no_action") if !markdown.contains("## No Action") => violations.push(format!(
                "first successful PR case {case_id} Markdown must show No Action"
            )),
            Some("blocked") if !markdown.contains("## Blocked") => violations.push(format!(
                "first successful PR case {case_id} Markdown must show Blocked"
            )),
            _ => {}
        }
    }
    Ok(())
}

fn validate_first_successful_pr_boundary_demo(
    root: &Path,
    case: &Value,
    case_id: &str,
    violations: &mut Vec<String>,
) -> Result<(), String> {
    let Some(demo_story) = json_string_field(case, "demo_story") else {
        violations.push(format!(
            "first successful PR case {case_id} is missing demo_story"
        ));
        return Ok(());
    };
    let story_path = Path::new(&demo_story);
    if story_path.is_absolute()
        || story_path
            .components()
            .any(|component| matches!(component, std::path::Component::ParentDir))
    {
        violations.push(format!(
            "first successful PR case {case_id} demo_story must be workspace-local"
        ));
        return Ok(());
    }
    let story_path = root.join(story_path);
    if !story_path.exists() {
        violations.push(format!(
            "first successful PR case {case_id} is missing {}",
            normalize_path(&story_path)
        ));
        return Ok(());
    }
    let story = read_text_lossy(&story_path)?;
    for required in [
        "ripr first-pr",
        "ripr outcome",
        "focused external proof",
        "cargo xtask fixtures boundary_gap",
        "fixtures/boundary_gap/calibration/before-targeted-test.repo-exposure.json",
        "fixtures/boundary_gap/calibration/after-targeted-test.repo-exposure.json",
        "fixtures/boundary_gap/calibration/targeted-test-outcome.md",
        "No runtime mutation proof",
        "No coverage adequacy",
        "No source edit or generated test from RIPR",
    ] {
        if !story.contains(required) {
            violations.push(format!(
                "{} is missing `{required}`",
                normalize_path(&story_path)
            ));
        }
    }
    Ok(())
}

const EDITOR_GAP_COCKPIT_FIXTURE_ROOT: &str = "fixtures/editor_gap_cockpit";
const EDITOR_GAP_COCKPIT_CASES: &[&str] = &[
    "rust_actionable",
    "typescript_preview_static_limit",
    "python_preview_static_limit",
    "disabled_language",
    "wrong_root",
    "stale_artifact",
    "no_actionable_gap",
];
const EDITOR_GAP_COCKPIT_EXPECTED_FILES: &[&str] = &[
    "lsp-diagnostics.json",
    "lsp-hover.md",
    "lsp-code-actions.json",
    "vscode-status.json",
    "gap-projection.json",
];

fn validate_editor_gap_cockpit_fixture_corpus(violations: &mut Vec<String>) -> Result<(), String> {
    let root = Path::new(EDITOR_GAP_COCKPIT_FIXTURE_ROOT);
    if !root.exists() {
        violations.push(format!(
            "editor gap cockpit fixture corpus is missing {}",
            normalize_path(root)
        ));
        return Ok(());
    }
    let spec = root.join("SPEC.md");
    if !spec.exists() {
        violations.push(format!(
            "editor gap cockpit fixture corpus is missing {}",
            normalize_path(&spec)
        ));
    } else {
        let spec_text = read_text_lossy(&spec)?;
        if !spec_text
            .lines()
            .any(|line| line.starts_with("Spec: RIPR-SPEC-0047"))
        {
            violations.push(format!(
                "{} is missing `Spec: RIPR-SPEC-0047`",
                normalize_path(&spec)
            ));
        }
        for heading in ["## Given", "## When", "## Then", "## Must Not"] {
            if !has_markdown_heading(&spec_text, heading) {
                violations.push(format!("{} is missing `{heading}`", normalize_path(&spec)));
            }
        }
    }

    for case in EDITOR_GAP_COCKPIT_CASES {
        validate_editor_gap_cockpit_fixture_case(root, case, violations)?;
    }
    Ok(())
}

fn validate_editor_gap_cockpit_fixture_case(
    root: &Path,
    case: &str,
    violations: &mut Vec<String>,
) -> Result<(), String> {
    let expected = root.join(case).join("expected");
    for file in EDITOR_GAP_COCKPIT_EXPECTED_FILES {
        let path = expected.join(file);
        if !path.exists() {
            violations.push(format!(
                "editor gap cockpit case {case} is missing {}",
                normalize_path(&path)
            ));
        }
    }
    let projection_path = expected.join("gap-projection.json");
    if projection_path.exists() {
        let projection = read_json_value(&projection_path)?;
        if json_string_field(&projection, "schema_version").as_deref() != Some("0.1") {
            violations.push(format!(
                "{} schema_version must be 0.1",
                normalize_path(&projection_path)
            ));
        }
        if json_string_field(&projection, "case").as_deref() != Some(case) {
            violations.push(format!(
                "{} case must be {case}",
                normalize_path(&projection_path)
            ));
        }
    }
    let diagnostics_path = expected.join("lsp-diagnostics.json");
    let actions_path = expected.join("lsp-code-actions.json");
    if diagnostics_path.exists() && actions_path.exists() {
        let diagnostics = read_json_value(&diagnostics_path)?;
        let actions = read_json_value(&actions_path)?;
        validate_editor_gap_case_semantics(case, &diagnostics, &actions, violations);
    }
    let hover_path = expected.join("lsp-hover.md");
    if hover_path.exists() {
        let hover = read_text_lossy(&hover_path)?;
        validate_editor_gap_hover(case, &hover, violations);
    }
    Ok(())
}

fn validate_editor_gap_case_semantics(
    case: &str,
    diagnostics: &Value,
    actions: &Value,
    violations: &mut Vec<String>,
) {
    let diagnostics_array = diagnostics
        .get("diagnostics")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let action_titles = actions
        .get("actions")
        .and_then(Value::as_array)
        .map(|items| {
            items
                .iter()
                .filter_map(|item| json_str_field(item, "title").map(str::to_string))
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    match case {
        "rust_actionable" => {
            require_gap_case_diagnostic(case, &diagnostics_array, "rust", "stable", violations);
            for title in [
                "Inspect gap: copy repair packet",
                "Write targeted test: open best related test",
                "Verify after test: copy verify command",
                "Review result: copy receipt command",
                "Refresh Analysis - Saved Workspace Check",
            ] {
                if !action_titles.iter().any(|value| value == title) {
                    violations.push(format!(
                        "editor gap cockpit case {case} is missing action `{title}`"
                    ));
                }
            }
        }
        "typescript_preview_static_limit" => {
            require_gap_case_diagnostic(
                case,
                &diagnostics_array,
                "typescript",
                "preview",
                violations,
            );
            require_action_title(
                case,
                &action_titles,
                "Inspect gap: copy static-limit note",
                violations,
            );
        }
        "python_preview_static_limit" => {
            require_gap_case_diagnostic(case, &diagnostics_array, "python", "preview", violations);
            require_action_title(
                case,
                &action_titles,
                "Inspect gap: copy static-limit note",
                violations,
            );
        }
        "disabled_language" | "wrong_root" | "stale_artifact" | "no_actionable_gap" => {
            if !diagnostics_array.is_empty() {
                violations.push(format!(
                    "editor gap cockpit case {case} must not project diagnostics"
                ));
            }
            if !(action_titles.len() == 1
                && action_titles[0] == "Refresh Analysis - Saved Workspace Check")
            {
                violations.push(format!(
                    "editor gap cockpit case {case} must fail closed to refresh-only actions"
                ));
            }
        }
        _ => {}
    }
}

fn require_gap_case_diagnostic(
    case: &str,
    diagnostics: &[Value],
    language: &str,
    language_status: &str,
    violations: &mut Vec<String>,
) {
    if diagnostics.len() != 1 {
        violations.push(format!(
            "editor gap cockpit case {case} must project exactly one diagnostic"
        ));
    }
    let Some(diagnostic) = diagnostics.first() else {
        return;
    };
    let data = diagnostic.get("data").unwrap_or(&Value::Null);
    if json_str_field(data, "language") != Some(language) {
        violations.push(format!(
            "editor gap cockpit case {case} diagnostic language must be {language}"
        ));
    }
    if json_str_field(data, "language_status") != Some(language_status) {
        violations.push(format!(
            "editor gap cockpit case {case} diagnostic language_status must be {language_status}"
        ));
    }
    if json_str_field(data, "canonical_gap_id").is_none() {
        violations.push(format!(
            "editor gap cockpit case {case} diagnostic must carry canonical_gap_id"
        ));
    }
}

fn require_action_title(
    case: &str,
    action_titles: &[String],
    title: &str,
    violations: &mut Vec<String>,
) {
    if !action_titles.iter().any(|value| value == title) {
        violations.push(format!(
            "editor gap cockpit case {case} is missing action `{title}`"
        ));
    }
}

fn validate_editor_gap_hover(case: &str, hover: &str, violations: &mut Vec<String>) {
    for heading in ["## Evidence boundary", "## Gap state", "## Limits"] {
        if !hover.contains(heading) {
            violations.push(format!(
                "editor gap cockpit case {case} hover is missing `{heading}`"
            ));
        }
    }
    if case.contains("preview") {
        let static_limit = hover.find("Static limit:");
        let action = hover.find("Suggested action:");
        if static_limit.is_none() || action.is_none() || static_limit > action {
            violations.push(format!(
                "editor gap cockpit case {case} hover must show static limits before action language"
            ));
        }
    }
}

const EDITOR_FIRST_RUN_USABILITY_FIXTURE_ROOT: &str = "fixtures/editor_first_run_usability";
const EDITOR_FIRST_RUN_USABILITY_CASES: &[&str] = &[
    "setup_ok",
    "server_missing",
    "config_missing",
    "language_disabled",
    "adapter_unavailable",
    "artifact_missing",
    "artifact_stale",
    "receipt_found",
    "receipt_gap_mismatch",
    "receipt_improved",
    "receipt_unchanged",
];
const EDITOR_FIRST_RUN_USABILITY_EXPECTED_FILES: &[&str] = &[
    "vscode-status.json",
    "setup-diagnosis.md",
    "lsp-code-actions.json",
    "receipt-status.json",
];

fn validate_editor_first_run_usability_fixture_corpus(
    violations: &mut Vec<String>,
) -> Result<(), String> {
    let root = Path::new(EDITOR_FIRST_RUN_USABILITY_FIXTURE_ROOT);
    if !root.exists() {
        violations.push(format!(
            "editor first-run usability fixture corpus is missing {}",
            normalize_path(root)
        ));
        return Ok(());
    }
    let spec = root.join("SPEC.md");
    if !spec.exists() {
        violations.push(format!(
            "editor first-run usability fixture corpus is missing {}",
            normalize_path(&spec)
        ));
    } else {
        let spec_text = read_text_lossy(&spec)?;
        for spec_id in ["RIPR-SPEC-0049", "RIPR-SPEC-0050"] {
            if !spec_text.lines().any(|line| line.contains(spec_id)) {
                violations.push(format!("{} is missing `{spec_id}`", normalize_path(&spec)));
            }
        }
        for heading in ["## Given", "## When", "## Then", "## Must Not"] {
            if !has_markdown_heading(&spec_text, heading) {
                violations.push(format!("{} is missing `{heading}`", normalize_path(&spec)));
            }
        }
    }

    for case in EDITOR_FIRST_RUN_USABILITY_CASES {
        validate_editor_first_run_usability_case(root, case, violations)?;
    }
    Ok(())
}

fn validate_editor_first_run_usability_case(
    root: &Path,
    case: &str,
    violations: &mut Vec<String>,
) -> Result<(), String> {
    let expected = root.join(case).join("expected");
    for file in EDITOR_FIRST_RUN_USABILITY_EXPECTED_FILES {
        let path = expected.join(file);
        if !path.exists() {
            violations.push(format!(
                "editor first-run usability case {case} is missing {}",
                normalize_path(&path)
            ));
        }
    }
    let status_path = expected.join("vscode-status.json");
    if status_path.exists() {
        let status = read_json_value(&status_path)?;
        validate_editor_first_run_status(case, &status, violations);
    }
    let actions_path = expected.join("lsp-code-actions.json");
    if actions_path.exists() {
        let actions = read_json_value(&actions_path)?;
        validate_editor_first_run_actions(case, &actions, violations);
    }
    let receipt_path = expected.join("receipt-status.json");
    if receipt_path.exists() {
        let receipt = read_json_value(&receipt_path)?;
        validate_editor_first_run_receipt(case, &receipt, violations);
    }
    let diagnosis_path = expected.join("setup-diagnosis.md");
    if diagnosis_path.exists() {
        let diagnosis = read_text_lossy(&diagnosis_path)?;
        for required in [
            "RIPR setup diagnosis",
            "Next safe action",
            "Limits",
            "no source edits",
        ] {
            if !diagnosis.contains(required) {
                violations.push(format!(
                    "editor first-run usability case {case} setup diagnosis is missing `{required}`"
                ));
            }
        }
    }
    Ok(())
}

fn validate_editor_first_run_status(case: &str, status: &Value, violations: &mut Vec<String>) {
    if json_string_field(status, "schema_version").as_deref() != Some("0.1") {
        violations.push(format!(
            "editor first-run usability case {case} vscode-status schema_version must be 0.1"
        ));
    }
    let expected_fixture = format!("editor_first_run_usability/{case}");
    if json_string_field(status, "fixture").as_deref() != Some(expected_fixture.as_str()) {
        violations.push(format!(
            "editor first-run usability case {case} vscode-status fixture must be {expected_fixture}"
        ));
    }
    if matches!(
        case,
        "setup_ok" | "receipt_found" | "receipt_improved" | "receipt_unchanged"
    ) && json_string_field(status, "next_safe_action").is_none()
    {
        violations.push(format!(
            "editor first-run usability case {case} must name a next_safe_action"
        ));
    }
    if matches!(
        case,
        "server_missing"
            | "language_disabled"
            | "adapter_unavailable"
            | "artifact_stale"
            | "receipt_gap_mismatch"
    ) && json_string_field(status, "projection").as_deref() != Some("fail_closed")
    {
        violations.push(format!(
            "editor first-run usability case {case} must fail closed"
        ));
    }
}

fn validate_editor_first_run_actions(case: &str, actions: &Value, violations: &mut Vec<String>) {
    if json_string_field(actions, "schema_version").as_deref() != Some("0.1") {
        violations.push(format!(
            "editor first-run usability case {case} lsp-code-actions schema_version must be 0.1"
        ));
    }
    let items = actions
        .get("actions")
        .and_then(Value::as_array)
        .map(Vec::as_slice)
        .unwrap_or(&[]);
    let first_repair_actions = items
        .iter()
        .filter(|item| {
            json_string_field(item, "title").as_deref() == Some("Copy first repair packet")
                || json_string_field(item, "command").as_deref() == Some("ripr.copyContext")
        })
        .collect::<Vec<_>>();
    let has_first_repair_packet = !first_repair_actions.is_empty();
    if matches!(
        case,
        "setup_ok" | "receipt_found" | "receipt_improved" | "receipt_unchanged"
    ) && !has_first_repair_packet
    {
        violations.push(format!(
            "editor first-run usability case {case} must include Copy first repair packet"
        ));
    }
    if matches!(
        case,
        "server_missing"
            | "config_missing"
            | "language_disabled"
            | "adapter_unavailable"
            | "artifact_missing"
            | "artifact_stale"
            | "receipt_gap_mismatch"
    ) && has_first_repair_packet
    {
        violations.push(format!(
            "editor first-run usability case {case} must not expose first repair packet"
        ));
    }
    for action in first_repair_actions {
        validate_editor_first_run_repair_action(case, action, violations);
    }
}

fn validate_editor_first_run_repair_action(
    case: &str,
    action: &Value,
    violations: &mut Vec<String>,
) {
    if json_string_field(action, "title").as_deref() != Some("Copy first repair packet") {
        violations.push(format!(
            "editor first-run usability case {case} first repair action must use the Copy first repair packet title"
        ));
    }
    if json_string_field(action, "command").as_deref() != Some("ripr.copyContext") {
        violations.push(format!(
            "editor first-run usability case {case} first repair action must use ripr.copyContext"
        ));
    }
    let packet = action
        .get("arguments")
        .and_then(Value::as_array)
        .and_then(|args| args.iter().find_map(|arg| json_string_field(arg, "packet")));
    let Some(packet) = packet else {
        violations.push(format!(
            "editor first-run usability case {case} first repair action must carry a packet argument"
        ));
        return;
    };
    for required in [
        "RIPR first repair packet",
        "Gap identity:",
        "Suggested action:",
        "Verify command:",
        "Receipt command:",
        "Limits and non-claims:",
    ] {
        if !packet.contains(required) {
            violations.push(format!(
                "editor first-run usability case {case} first repair packet is missing `{required}`"
            ));
        }
    }
}

fn validate_editor_first_run_receipt(case: &str, receipt: &Value, violations: &mut Vec<String>) {
    if json_string_field(receipt, "schema_version").as_deref() != Some("0.1") {
        violations.push(format!(
            "editor first-run usability case {case} receipt-status schema_version must be 0.1"
        ));
    }
    let state = json_string_field(receipt, "receipt_state");
    let expected_state = match case {
        "receipt_found" => Some("receipt_found"),
        "receipt_gap_mismatch" => Some("receipt_gap_mismatch"),
        "receipt_improved" => Some("receipt_movement_improved"),
        "receipt_unchanged" => Some("receipt_movement_unchanged"),
        "artifact_stale" => Some("receipt_stale"),
        _ => None,
    };
    if let Some(expected_state) =
        expected_state.filter(|expected| state.as_deref() != Some(*expected))
    {
        violations.push(format!(
            "editor first-run usability {case} must record {expected_state}"
        ));
    }
    if json_bool_field(receipt, "runtime_adequacy_claim") != Some(false) {
        violations.push(format!(
            "editor first-run usability case {case} receipt-status must deny runtime_adequacy_claim"
        ));
    }
    if json_bool_field(receipt, "gate_eligibility_claim") != Some(false) {
        violations.push(format!(
            "editor first-run usability case {case} receipt-status must deny gate_eligibility_claim"
        ));
    }
}

